let data = $input.first().json;
if (data.body && typeof data.body === 'object') {
  data = data.body;
}

const hr = parseFloat(data.heart_rate || data.heartRate || 0);
const glRaw = parseFloat(data.glucose || 0);
const gl = Number.isFinite(glRaw) ? Number((glRaw / 18).toFixed(1)) : 0;
const wt = parseFloat(data.weight || data.body_mass || 0);
const sl = parseFloat(data.sleep || data.sleep_hours || 0);

const hrAlert = hr > 85;
const glAlert = gl > 6.0;
const slAlert = sl < 6;
const status = (hrAlert || glAlert || slAlert) ? '🔴' : '🟢';
const ts = data.timestamp || new Date().toISOString();

const icon = bad => bad ? '⚠️' : '✅';
const line = (label, val, unit, bad, note) =>
  icon(bad) + ' ' + label + ': ' + (val || '-') + ' ' + unit + (bad ? ' — ' + note : '');

const msg = [
  '🏥 Health Report · ' + ts, '',
  line('Пульс', hr, 'уд/мин', hrAlert, 'выше нормы'),
  line('Глюкоза', gl, 'mmol/L', glAlert, 'выше нормы'),
  line('Вес', wt, 'кг', false, ''),
  line('Сон', sl, 'ч', slAlert, 'мало'), '',
  status + (status === '🔴' ? ' Есть отклонения' : ' Всё в норме'),
].join('\n');

return [{ json: {
  timestamp: ts,
  heart_rate: hr, glucose_raw: glRaw, glucose_mmol: gl, weight: wt, sleep_hours: sl,
  hr_alert: hrAlert, glucose_alert: glAlert, sleep_alert: slAlert,
  status, telegram_text: msg,
  csv_row: ts + ',' + hr + ',' + glRaw + ',' + gl + ',' + wt + ',' + sl + ',' + hrAlert + ',' + glAlert + ',' + slAlert + ',' + status
}}];
